// Logo FINMED — PNG embebido em base64 (a partir dos assets oficiais)
// Variante "white" usa fundo escuro; "dark" usa fundo claro

const LOGO_WHITE = 'data:image/png;base64,';
const LOGO_DARK = 'data:image/png;base64,';

export function Logo({ variant = 'white', className = '' }) {
  const src = variant === 'white' ? LOGO_WHITE : LOGO_DARK;
  return <img src={src} alt="FINMED" className={className} />;
}
